import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { createClient } from '@supabase/supabase-js';
import DOMPurify from 'dompurify';

const supabase = createClient(
  'https://gwmpdgjvcjzndbloctla.supabase.co',
  'sb_publishable_Kor1B60TEAKofYE75aW7Ow_WL0cPOa8'
);

interface SharedLink {
  content_html: string;
  content_type: string;
  metadata: Record<string, unknown>;
  created_at: string;
}

export default function SharePage() {
  const { slug } = useParams<{ slug: string }>();
  const [content, setContent] = useState<SharedLink | null>(null);
  const [loading, setLoading] = useState(true);
  const [notFound, setNotFound] = useState(false);
  const [feedbackName, setFeedbackName] = useState('');
  const [feedbackText, setFeedbackText] = useState('');
  const [feedbackSent, setFeedbackSent] = useState(false);

  useEffect(() => {
    async function load() {
      const { data } = await supabase
        .from('shared_links')
        .select('content_html, content_type, metadata, created_at')
        .eq('slug', slug)
        .maybeSingle();

      if (data) {
        setContent(data);
        // Increment view count
        await supabase.rpc('increment_view_count', { link_slug: slug });
      } else {
        setNotFound(true);
      }
      setLoading(false);
    }
    load();
  }, [slug]);

  async function handleFeedback(e: React.FormEvent) {
    e.preventDefault();
    if (!feedbackText.trim()) return;

    // Get link ID
    const { data: link } = await supabase
      .from('shared_links')
      .select('id')
      .eq('slug', slug)
      .single();

    if (link) {
      await supabase.from('share_feedback').insert({
        link_id: link.id,
        reviewer_name: feedbackName || 'Anonymous',
        feedback_text: feedbackText,
      });
    }
    setFeedbackSent(true);
  }

  if (loading) {
    return <div style={{ textAlign: 'center', padding: '4rem', color: 'var(--text-secondary)' }}>Loading...</div>;
  }

  if (notFound) {
    return (
      <div style={{ textAlign: 'center', padding: '4rem' }}>
        <h2 style={{ color: 'var(--text-primary)' }}>Link not found</h2>
        <p style={{ color: 'var(--text-secondary)' }}>This shared link may have expired or doesn't exist.</p>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      <div style={{ marginBottom: '1.5rem', textAlign: 'center' }}>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.82rem' }}>
          Shared via TailorMeSwiftly
        </p>
      </div>

      {/* Content */}
      <div
        style={{
          background: '#fff',
          color: '#2A2E38',
          padding: '2rem',
          borderRadius: '2px',
          marginBottom: '2rem',
          boxShadow: 'var(--brutal-shadow)',
        }}
        dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(content!.content_html) }}
      />

      {/* Feedback Form */}
      <div className="glass-panel" style={{ padding: '1.5rem' }}>
        <h3 style={{ fontSize: '1rem', marginBottom: '0.75rem', color: 'var(--text-primary)' }}>
          <i className="fa-solid fa-comment-dots" /> Leave Feedback
        </h3>

        {feedbackSent ? (
          <p style={{ color: 'var(--success-color, #10b981)', fontSize: '0.9rem' }}>
            Thanks for your feedback!
          </p>
        ) : (
          <form onSubmit={handleFeedback} style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
            <input
              type="text"
              value={feedbackName}
              onChange={e => setFeedbackName(e.target.value)}
              placeholder="Your name (optional)"
            />
            <textarea
              value={feedbackText}
              onChange={e => setFeedbackText(e.target.value)}
              placeholder="Share your thoughts, suggestions, or feedback..."
              rows={4}
              required
              style={{ resize: 'vertical' }}
            />
            <button
              type="submit"
              className="btn secondary-btn"
              style={{ padding: '0.6rem', cursor: 'pointer' }}
            >
              Send Feedback
            </button>
          </form>
        )}
      </div>
    </div>
  );
}
